={{ 
  JSON.stringify({ 
    messages: (function() { 
      const data = $input.first().json; 
      const history = data.body.messages; 
      const calc = data.tax_calc; 
      const systemMsg = history.find(m => m.role === 'system'); 
      const otherMsgs = history.filter(m => m.role !== 'system'); 
      let taxContext = "";
      if (calc) {
          taxContext = `\n\nCALCULATION RESULT (Usa esto para responder de forma amigable):\nSueldo Bruto Mensual: $${Math.round(calc.bruto).toLocaleString()}\nNeto Estimado (con Ganancias y Aportes): $${Math.round(calc.netoMensual).toLocaleString()}\nRetención mensual Ganancias: $${Math.round(calc.impuestoMensual).toLocaleString()}\nDeducciones aplicadas: ${calc.hijos} hijos, ${calc.conyuge ? 'Cónyuge' : 'Sin cónyuge'}.\nExplica que es un cálculo de Ganancias 2026 y ofrece agendar una charla para optimización financiera [ACTION:CALENDLY].`;
      } else {
          taxContext = "\n\nINSTRUCCIÓN: El usuario quiere calcular su sueldo pero no proporcionó el monto bruto. Pídele amablemente el sueldo bruto mensual y si tiene hijos o cónyuge para ser exacto.";
      }
      return [ 
        { role: 'system', content: (systemMsg?.content || '') + taxContext }, 
        ...otherMsgs 
      ]; 
    })(), 
    model: 'zai-org/GLM-4.7-Flash:novita', 
    stream: false 
  }) 
}}
